package org.apache.commons.csv;
import java.io.BufferedReader;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.spy;
import static org.mockito.Mockito.doReturn;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class ExtendedBufferedReaderTest {

    private ExtendedBufferedReader readerSpy;

    @BeforeEach
    void setUp() {
        Reader dummyReader = new Reader() {
            @Override
            public int read(char[] cbuf, int off, int len) {
                return -1; // EOF
            }
            @Override
            public void close() {}
        };
        readerSpy = spy(new ExtendedBufferedReader(dummyReader));
    }

    @Test
    void testReadReturnsCharAndUpdatesLastCharWithoutNewline() throws IOException {
        doReturn((int) 'a').when(readerSpy).read();
        // call real method under test
        int result = readerSpy.read();
        assertEquals('a', result);
        // lineCounter should remain 0
        int lineCounter = getPrivateIntField(readerSpy, "lineCounter");
        assertEquals(0, lineCounter);
        int lastChar = getPrivateIntField(readerSpy, "lastChar");
        assertEquals('a', lastChar);
    }

    @Test
    void testReadReturnsNewlineAndIncrementsLineCounter() throws IOException {
        doReturn((int) '\n').when(readerSpy).read();
        int result = readerSpy.read();
        assertEquals('\n', result);
        int lineCounter = getPrivateIntField(readerSpy, "lineCounter");
        assertEquals(1, lineCounter);
        int lastChar = getPrivateIntField(readerSpy, "lastChar");
        assertEquals('\n', lastChar);
    }

    @Test
    void testReadReturnsEndOfStream() throws IOException {
        doReturn(ExtendedBufferedReader.END_OF_STREAM).when(readerSpy).read();
        int result = readerSpy.read();
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, result);
        int lineCounter = getPrivateIntField(readerSpy, "lineCounter");
        assertEquals(0, lineCounter);
        int lastChar = getPrivateIntField(readerSpy, "lastChar");
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);
    }

    private int getPrivateIntField(Object obj, String fieldName) {
        try {
            var field = obj.getClass().getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.getInt(obj);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
